// SRCMB.S16.Q.QACC
//
// ESP.SRCMB.S16.Q.QACC - Shift Right Concatenated with saturation from QACC using Qw vector
// This instruction extracts 8 64-bit Data segments from QACC_H and QACC_L,
// performs arithmetic right shift on each segment using shift amounts from Qw vector,
// saturates results to 16-bit signed values, and writes them to Qu register.
// Qw contains 8 16-bit shift amounts (each value clamped to 0x3f max)
// Sel2 selects saturation mode: 0 = no saturation, 1 = saturate to 16-bit signed
// CHECK-LABEL: define dso_local ptr @test_srcmb_s16_q_qacc(
// CHECK-SAME: ptr noundef [[SRC_DATA:%.*]], ptr noundef [[SRC_QW:%.*]], ptr noundef [[DST_QU:%.*]]) local_unnamed_addr #[[ATTR2:[0-9]+]] {
